/**
 * EventDebugPanel — shell-only diagnostics panel for cross-app event flows.
 * Captures event-bus payloads in real time to support workflow validation.
 */
import React, { useEffect, useMemo, useState } from 'react';
import Box from '@mui/material/Box';
import Typography from '@mui/material/Typography';
import { AppEvent, eventBus } from '@shared/event-bus';
import { Button, Card, StatusBadge } from '@shared/ui-components';

// Generated by GitHub Copilot
const MAX_EVENTS = 120;

interface EventLogEntry {
    id: string;
    event: AppEvent;
    payload: string;
    emittedAt: string;
}

/**
 * Stringifies event payload for debugger rendering without throwing.
 */
function toPayloadString(payload: unknown): string {
    try {
        return JSON.stringify(payload, null, 2);
    } catch {
        return String(payload);
    }
}

const EventDebugPanel: React.FC = () => {
    const [events, setEvents] = useState<EventLogEntry[]>([]);

    useEffect(() => {
        const eventNames = Object.values(AppEvent);

        const unsubscribeCallbacks = eventNames.map((eventName) => (
            eventBus.on(eventName, (payload) => {
                setEvents((prev) => [
                    {
                        id: `${eventName}-${Date.now()}-${Math.random().toString(16).slice(2, 8)}`,
                        event: eventName,
                        payload: toPayloadString(payload),
                        emittedAt: new Date().toISOString(),
                    },
                    ...prev,
                ].slice(0, MAX_EVENTS));
            })
        ));

        return () => {
            unsubscribeCallbacks.forEach((unsubscribe) => unsubscribe());
        };
    }, []);

    const eventCounts = useMemo(() => {
        const counts: Record<string, number> = {};
        for (const event of events) {
            counts[event.event] = (counts[event.event] ?? 0) + 1;
        }
        return counts;
    }, [events]);

    return (
        <section aria-label="Event Debug Panel">
            <Typography variant="h5" component="h1" fontWeight={700} sx={{ mb: 1 }}>
                Event Debug
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
                Live feed of AppEvent traffic across shell and remote modules.
            </Typography>

            <Card title="Event Counters" style={{ marginBottom: '1rem' }}>
                <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1 }}>
                    {Object.values(AppEvent).map((eventName) => (
                        <Box
                            key={eventName}
                            sx={{
                                display: 'flex',
                                alignItems: 'center',
                                gap: 0.5,
                                px: 1,
                                py: 0.5,
                                borderRadius: 1,
                                border: '1px solid',
                                borderColor: 'divider',
                            }}
                        >
                            <StatusBadge status="info" label={eventName} />
                            <Typography variant="caption" fontWeight={600}>
                                {eventCounts[eventName] ?? 0}
                            </Typography>
                        </Box>
                    ))}
                </Box>
            </Card>

            <Card title="Recent Events (Newest First)">
                <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 1 }}>
                    <Typography variant="caption" color="text.secondary">
                        Captured: {events.length} / {MAX_EVENTS}
                    </Typography>
                    <Button variant="secondary" size="sm" onClick={() => setEvents([])}>
                        Clear
                    </Button>
                </Box>

                {events.length === 0 ? (
                    <Typography variant="body2" color="text.secondary">
                        No events captured yet. Trigger actions in any module to see traffic.
                    </Typography>
                ) : (
                    <Box component="ul" sx={{ listStyle: 'none', p: 0, m: 0, display: 'grid', gap: 1 }}>
                        {events.map((entry) => (
                            <Box
                                component="li"
                                key={entry.id}
                                sx={{
                                    p: 1,
                                    borderRadius: 1,
                                    border: '1px solid',
                                    borderColor: 'divider',
                                    backgroundColor: 'background.default',
                                }}
                            >
                                <Typography variant="caption" color="text.secondary" sx={{ display: 'block' }}>
                                    {entry.emittedAt}
                                </Typography>
                                <Typography variant="body2" fontWeight={700} sx={{ mb: 0.5 }}>
                                    {entry.event}
                                </Typography>
                                <Box
                                    component="pre"
                                    sx={{
                                        m: 0,
                                        p: 1,
                                        borderRadius: 1,
                                        backgroundColor: 'background.paper',
                                        border: '1px solid',
                                        borderColor: 'divider',
                                        whiteSpace: 'pre-wrap',
                                        wordBreak: 'break-word',
                                        fontSize: '0.75rem',
                                    }}
                                >
                                    {entry.payload}
                                </Box>
                            </Box>
                        ))}
                    </Box>
                )}
            </Card>
        </section>
    );
};

export default EventDebugPanel;
